questions.question:
次の関数に対して、オブジェクトの引数をデストラクチャリングしてそれぞれのプロパティにアクセスしてください。

function showDetails(user) {
  console.log(user.name);
  console.log(user.age);
}

questions.answer:
function showDetails({ name, age }) {
  console.log(name);
  console.log(age);
}

showDetails({ name: 'Alice', age: 25 });  // console.logで 'Alice' と '25' を表示

questions.question:
次の関数に対して、引数が渡されなかった場合にはデフォルト値として10を使用するように設定してください。

function addTen(num) {
  return num + 10;
}

questions.answer:
function addTen(num = 10) {
  return num + 10;
}

console.log(addTen());  // console.logで '20' を表示

function checkNumber(num) {
  if (typeof num === 'number') {
    return num;
  } else {
    console.log('Error: Argument is not a number');
  }
}

console.log(checkNumber('hello'));  // console.logで 'Error: Argument is not a number' を表示

function addNumbers(...nums) {
  // reduceを使用して配列の全要素を合計
  return nums.reduce((sum, num) => sum + num, 0);
}

console.log(addNumbers(1, 2, 3, 4, 5));  // console.logで '15' を表示

function addWithDefault(a, b = 10) {
  // aとbを加算
  return a + b;
}

console.log(addWithDefault(5));  // console.logで '15' を表示

function introduce({name, age}) {
  // テンプレートリテラルを使用して文字列を作成
  return `Hello, my name is ${name} and I am ${age} years old.`;
}

console.log(introduce({name: 'John', age: 30}));  // console.logで 'Hello, my name is John and I am 30 years old.' を表示

function sum(...nums) {
  // reduce関数を使って、numsの全要素を合計する
  return nums.reduce((total, num) => total + num, 0);
}

console.log(sum(1, 2, 3, 4, 5));  // console.logで '15' を表示

function introduce({name, age}) {
  // テンプレートリテラルを使用して文字列を作成
  return `Hello, my name is ${name} and I am ${age} years old.`;
}

console.log(introduce({name: 'John', age: 30}));  // console.logで 'Hello, my name is John and I am 30 years old.' を表示

function multiply(a, b = 1) {
  // bが指定されない場合、1がデフォルト値として使われる
  return a * b;
}

console.log(multiply(5, 2));  // console.logで '10' を表示
console.log(multiply(5));     // console.logで '5' を表示

function splitArray([a, b, c]) {
  // 配列の各要素を個別の変数に代入
  return `${a} - ${b} - ${c}`;
}

console.log(splitArray(['Hello', 'World', '!']));  // console.logで 'Hello - World - !' を表示

function splitObject({name, age}) {
  // オブジェクトのプロパティを個別の変数に代入
  return `${name} is ${age} years old.`;
}

console.log(splitObject({name: 'John', age: 25}));  // console.logで 'John is 25 years old.' を表示

function countDown(n) {
  // nが0以下になったら終了
  if (n <= 0) return;
  console.log(n);
  // nから1を引いた値を引数にして、自身を再び呼び出す
  countDown(n - 1);
}

countDown(5);  // console.logで '5', '4', '3', '2', '1' を順に表示

function executeFunc(func) {
  // 受け取った関数を実行し、その結果を返す
  return func();
}

const sayHello = function() {
  return 'Hello!';
}

console.log(executeFunc(sayHello));  // console.logで 'Hello!' を表示

function getMax(arr) {
  let max = arr[0];
  for (let i = 1; i < arr.length; i++) {
    // もし、現在の要素がmaxより大きければ、maxを更新
    if (arr[i] > max) {
      max = arr[i];
    }
  }
  return max;
}

console.log(getMax([3, 5, 2, 8, 1]));  // console.logで '8' を表示

function average(...nums) {
  let sum = 0;
  for (let num of nums) {
    sum += num;
  }
  return sum / nums.length;
}

console.log(average(1, 2, 3, 4, 5));  // console.logで '3' を表示

function higherOrderFunction(num, callback) {
  // callbackを実行して、その結果を返す
  return callback(num);
}

const double = function(num) {
  return num * 2;
};

console.log(higherOrderFunction(5, double));  // console.logで '10' を表示

function multiply(a, b = 10) {
  return a * b;
}

console.log(multiply(5));  // console.logで '50' を表示
console.log(multiply(5, 2));  // console.logで '10' を表示

questions.question:
JavaScriptでは、関数の引数としてオブジェクトを受け取ることができます。以下の形式のオブジェクトを引数として受け取り、'Hello, [name]! You are [age] years old.'という形式の文字列を返す関数を作成してください。

オブジェクトの形式：

{
  name: 'John',
  age: 20
}

questions.answer:
function greet(person) {
  return `Hello, ${person.name}! You are ${person.age} years old.`;
}

console.log(greet({name: 'John', age: 20}));  // console.logで 'Hello, John! You are 20 years old.' を表示
